// Script: generar_142_chiqui_ladeado_registro.js
// Reemplaza chiqui_ladeado.png en public/chiqui/ con el PNG correcto
// del nuevo set (cabeza inclinada con lengua afuera) para el botón
// "¿Hoy no notaste nada raro?" en el registro diario.

const fs = require('fs'); const path = require('path');
function png(r, b64) {
  const f = path.join(...r.split('/')); const d = path.dirname(f);
  if (!fs.existsSync(d)) fs.mkdirSync(d,{recursive:true});
  fs.writeFileSync(f, Buffer.from(b64,'base64')); console.log('OK: '+f);
}
function tsx(r, b64) {
  const f = path.join(...r.split('/')); const d = path.dirname(f);
  if (!fs.existsSync(d)) fs.mkdirSync(d,{recursive:true});
  fs.writeFileSync(f, Buffer.from(b64,'base64').toString('utf8')); console.log('OK: '+f);
}
png('public/chiqui/chiqui_ladeado.png', "");
tsx('app/registro-diario/page.tsx', "");
